1157: 					--endLineNumber;
1158: 				}
1159: 				if (endLineNumber > selection.startLineNumber) {
1160: 					collapseRanges.push({
1161: 						startLineNumber: selection.startLineNumber,
1162: 						endLineNumber: endLineNumber,
1163: 						type: undefined,
1164: 						isCollapsed: true,
1165: 						source: FoldSource.userDefined
1166: 					});
1167: 					editor.setSelection({
1168: 						startLineNumber: selection.startLineNumber,
1169: 						startColumn: 1,
1170: 						endLineNumber: selection.startLineNumber,
1171: 						endColumn: 1
1172: 					});
1173: 				}
1174: 			}
1175: 			if (collapseRanges.length > 0) {
1176: 				collapseRanges.sort((a, b) => {
1177: 					return a.startLineNumber - b.startLineNumber;
1178: 				});
1179: 				const newRanges = FoldingRegions.sanitizeAndMerge(foldingModel.regions, collapseRanges, editor.getModel()?.getLineCount());
1180: 				foldingModel.updatePost(FoldingRegions.fromFoldRanges(newRanges));
1181: 			}
