1294: 	if (!configurationService.getValue('editor.folding', { resource })) {
1295: 		return [];
1296: 	}
1297: 
1298: 	const languageConfigurationService = accessor.get(ILanguageConfigurationService);
1299: 
1300: 	const strategy = configurationService.getValue('editor.foldingStrategy', { resource });
1301: 	const foldingLimitReporter = {
1302: 		get limit() {
1303: 			return <number>configurationService.getValue('editor.foldingMaximumRegions', { resource });
1304: 		},
1305: 		update: (computed: number, limited: number | false) => { }
1306: 	};
1307: 
1308: 	const indentRangeProvider = new IndentRangeProvider(model, languageConfigurationService, foldingLimitReporter);
1309: 	let rangeProvider: RangeProvider = indentRangeProvider;
1310: 	if (strategy !== 'indentation') {
1311: 		const providers = FoldingController.getFoldingRangeProviders(languageFeaturesService, model);
1312: 		if (providers.length) {
1313: 			rangeProvider = new SyntaxRangeProvider(model, providers, () => { }, foldingLimitReporter, indentRangeProvider);
1314: 		}
1315: 	}
1316: 	const ranges = await rangeProvider.compute(CancellationToken.None);
1317: 	const result: FoldingRange[] = [];
1318: 	try {
1319: 		if (ranges) {
1320: 			for (let i = 0; i < ranges.length; i++) {
1321: 				const type = ranges.getType(i);
1322: 				result.push({ start: ranges.getStartLineNumber(i), end: ranges.getEndLineNumber(i), kind: type ? FoldingRangeKind.fromValue(type) : undefined });
1323: 			}
1324: 		}
