115: interface PreviousRegion {
116: 	indent: number; // indent or -2 if a marker
117: 	endAbove: number; // end line number for the region above
118: 	line: number; // start line of the region. Only used for marker regions.
119: }
120: 
121: const foldingRangesLimitDefault: FoldingLimitReporter = {
122: 	limit: MAX_FOLDING_REGIONS_FOR_INDENT_DEFAULT,
123: 	update: () => { }
124: };
