import assert from 'assert';
import { ensureNoDisposablesAreLeakedInTestSuite } from '../../../../../base/test/common/utils.js';
import { NamedRegionProvider } from '../../browser/namedRegionProvider.js';
import { createTextModel } from '../../../../test/common/testTextModel.js';

suite('Named Region Provider', () => {
	ensureNoDisposablesAreLeakedInTestSuite();

	test('Extract single named region', () => {
		const model = createTextModel([
			'// #region MySection',
			'const x = 1;',
			'// #endregion'
		].join('\n'));

		const regions = NamedRegionProvider.extractNamedRegions(model);

		assert.strictEqual(regions.length, 1);
		assert.strictEqual(regions[0].name, 'MySection');
		assert.strictEqual(regions[0].startLineNumber, 1);
		assert.strictEqual(regions[0].endLineNumber, 3);

		model.dispose();
	});

	test('Extract multiple named regions', () => {
		const model = createTextModel([
			'// #region Section1',
			'const x = 1;',
			'// #endregion',
			'',
			'// #region Section2',
			'const y = 2;',
			'// #endregion'
		].join('\n'));

		const regions = NamedRegionProvider.extractNamedRegions(model);

		assert.strictEqual(regions.length, 2);
		assert.strictEqual(regions[0].name, 'Section1');
		assert.strictEqual(regions[0].startLineNumber, 1);
		assert.strictEqual(regions[0].endLineNumber, 3);
		assert.strictEqual(regions[1].name, 'Section2');
		assert.strictEqual(regions[1].startLineNumber, 5);
		assert.strictEqual(regions[1].endLineNumber, 7);

		model.dispose();
	});

	test('Extract nested named regions', () => {
		const model = createTextModel([
			'// #region Outer',
			'// #region Inner',
			'const x = 1;',
			'// #endregion',
			'// #endregion'
		].join('\n'));

		const regions = NamedRegionProvider.extractNamedRegions(model);

		assert.strictEqual(regions.length, 2);
		assert.strictEqual(regions[0].name, 'Inner');
		assert.strictEqual(regions[0].startLineNumber, 2);
		assert.strictEqual(regions[0].endLineNumber, 4);
		assert.strictEqual(regions[1].name, 'Outer');
		assert.strictEqual(regions[1].startLineNumber, 1);
		assert.strictEqual(regions[1].endLineNumber, 5);

		model.dispose();
	});

	test('Extract named regions with whitespace', () => {
		const model = createTextModel([
			'  // #region MySection',
			'\tconst x = 1;',
			'  // #endregion'
		].join('\n'));

		const regions = NamedRegionProvider.extractNamedRegions(model);

		assert.strictEqual(regions.length, 1);
		assert.strictEqual(regions[0].name, 'MySection');
		assert.strictEqual(regions[0].startLineNumber, 1);
		assert.strictEqual(regions[0].endLineNumber, 3);

		model.dispose();
	});

	test('Extract named regions with block comments', () => {
		const model = createTextModel([
			'/* #region MySection */',
			'const x = 1;',
			'/* #endregion */'
		].join('\n'));

		const regions = NamedRegionProvider.extractNamedRegions(model);

		assert.strictEqual(regions.length, 1);
		assert.strictEqual(regions[0].name, 'MySection');
		assert.strictEqual(regions[0].startLineNumber, 1);
		assert.strictEqual(regions[0].endLineNumber, 3);

		model.dispose();
	});

	test('Handle unmatched region start', () => {
		const model = createTextModel([
			'// #region MySection',
			'const x = 1;',
			'const y = 2;'
		].join('\n'));

		const regions = NamedRegionProvider.extractNamedRegions(model);

		// Unmatched region start should not be included
		assert.strictEqual(regions.length, 0);

		model.dispose();
	});

	test('Handle unmatched region end', () => {
		const model = createTextModel([
			'const x = 1;',
			'const y = 2;',
			'// #endregion'
		].join('\n'));

		const regions = NamedRegionProvider.extractNamedRegions(model);

		// Unmatched region end should be ignored
		assert.strictEqual(regions.length, 0);

		model.dispose();
	});

	test('Extract regions with spaces in name', () => {
		const model = createTextModel([
			'// #region My Section Name',
			'const x = 1;',
			'// #endregion'
		].join('\n'));

		const regions = NamedRegionProvider.extractNamedRegions(model);

		assert.strictEqual(regions.length, 1);
		assert.strictEqual(regions[0].name, 'My Section Name');
		assert.strictEqual(regions[0].startLineNumber, 1);
		assert.strictEqual(regions[0].endLineNumber, 3);

		model.dispose();
	});

	test('Regions sorted by start line', () => {
		const model = createTextModel([
			'// #region Section3',
			'const z = 3;',
			'// #endregion',
			'// #region Section1',
			'const x = 1;',
			'// #endregion',
			'// #region Section2',
			'const y = 2;',
			'// #endregion'
		].join('\n'));

		const regions = NamedRegionProvider.extractNamedRegions(model);

		assert.strictEqual(regions.length, 3);
		assert.strictEqual(regions[0].name, 'Section3');
		assert.strictEqual(regions[0].startLineNumber, 1);
		assert.strictEqual(regions[1].name, 'Section1');
		assert.strictEqual(regions[1].startLineNumber, 4);
		assert.strictEqual(regions[2].name, 'Section2');
		assert.strictEqual(regions[2].startLineNumber, 7);

		model.dispose();
	});

	test('Empty file', () => {
		const model = createTextModel('');

		const regions = NamedRegionProvider.extractNamedRegions(model);

		assert.strictEqual(regions.length, 0);

		model.dispose();
	});

	test('File with no regions', () => {
		const model = createTextModel([
			'const x = 1;',
			'const y = 2;',
			'const z = 3;'
		].join('\n'));

		const regions = NamedRegionProvider.extractNamedRegions(model);

		assert.strictEqual(regions.length, 0);

		model.dispose();
	});
});

